@app.route('/documents/search', methods=['GET'])
def search_documents():
    query = {}
    
    title = request.args.get('title')
    if title:
        query['title'] = {'$regex': title, '$options': 'i'}
    
    category = request.args.get('category')
    if category:
        query['category'] = category
    
    tags = request.args.get('tags')
    if tags:
        tag_list = tags.split(',')
        query['tags'] = {'$in': tag_list}
    
    status = request.args.get('status')
    if status:
        query['status'] = status
    
    author_id = request.args.get('author_id')
    if author_id:
        query['author_id'] = author_id
    
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = DESCENDING if request.args.get('sort_order', 'desc') == 'desc' else ASCENDING
    
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 10))
    skip = (page - 1) * per_page
    
    documents = list(documents_collection.find(query).sort(sort_by, sort_order).skip(skip).limit(per_page))
    documents = [serialize_doc(doc) for doc in documents]
    total = documents_collection.count_documents(query)
    
    return jsonify({
        'documents': documents,
        'total': total,
        'page': page,
        'per_page': per_page
    }), 200


@app.route('/documents/stats', methods=['GET'])
def document_stats():
    pipeline = [
        {
            '$group': {
                '_id': '$category',
                'count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'avg_views': {'$avg': '$views'},
                'avg_likes': {'$avg': '$likes'}
            }
        },
        {
            '$sort': {'count': -1}
        }
    ]
    
    stats = list(documents_collection.aggregate(pipeline))
    return jsonify({'stats': stats}), 200


@app.route('/documents/popular', methods=['GET'])
def popular_documents():
    limit = int(request.args.get('limit', 10))
    
    pipeline = [
        {
            '$match': {'status': 'published'}
        },
        {
            '$addFields': {
                'popularity_score': {
                    '$add': [
                        {'$multiply': ['$views', 1]},
                        {'$multiply': ['$likes', 5]}
                    ]
                }
            }
        },
        {
            '$sort': {'popularity_score': -1}
        },
        {
            '$limit': limit
        },
        {
            '$lookup': {
                'from': 'users',
                'localField': 'author_id',
                'foreignField': '_id',
                'as': 'author'
            }
        },
        {
            '$unwind': {
                'path': '$author',
                'preserveNullAndEmptyArrays': True
            }
        }
    ]
    
    documents = list(documents_collection.aggregate(pipeline))
    documents = [serialize_doc(doc) for doc in documents]
    
    for doc in documents:
        if 'author' in doc and '_id' in doc['author']:
            doc['author']['_id'] = str(doc['author']['_id'])
    
    return jsonify({'documents': documents}), 200


@app.route('/documents/by-author/<author_id>', methods=['GET'])
def documents_by_author(author_id):
    pipeline = [
        {
            '$match': {'author_id': author_id}
        },
        {
            '$group': {
                '_id': '$status',
                'count': {'$sum': 1},
                'documents': {'$push': '$$ROOT'}
            }
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    
    for result in results:
        result['documents'] = [serialize_doc(doc) for doc in result['documents']]
    
    return jsonify({'results': results}), 200


@app.route('/analytics/top-authors', methods=['GET'])
def top_authors():
    limit = int(request.args.get('limit', 10))
    
    pipeline = [
        {
            '$match': {'status': 'published'}
        },
        {
            '$group': {
                '_id': '$author_id',
                'document_count': {'$sum': 1},
                'total_views': {'$sum': '$views'},
                'total_likes': {'$sum': '$likes'},
                'avg_views': {'$avg': '$views'}
            }
        },
        {
            '$sort': {'document_count': -1}
        },
        {
            '$limit': limit
        }
    ]
    
    authors = list(documents_collection.aggregate(pipeline))
    
    for author in authors:
        if author['_id']:
            user = users_collection.find_one({'_id': ObjectId(author['_id'])})
            if user:
                author['author_info'] = serialize_doc(user)
    
    return jsonify({'top_authors': authors}), 200


